import dspy
import vex

@vex.verify(policies=[{'name': 'no_pii', 'PII_ENTITIES': ['NAME', 'SSN', 'STUDENT_ID']}],
           on_fail='block')
def safe_tutor_forward(self, student_query):
    # DSPy tutor module
    prediction = self.tutor(student_query)
    return prediction

class StudentTutor(dspy.Module):
    def __init__(self):
        super().__init__()
        self.tutor = dspy.ChainOfThought('query -> answer')

    def forward(self, student_query):
        return safe_tutor_forward(self, student_query)

# Usage
vex.init(project='education-dspy')
tutor = StudentTutor()
response = tutor('Explain fractions to 4th grader')

import dspy
import vex

@vex.verify(policies=[{'name': 'coppa_safe', 'max_reading_level': 4, 'no_violence': True, 'no_explicit': True}],
           on_fail='review')
def coppa_safe_lesson(self, grade_level, topic):
    prediction = self.generate_lesson(grade_level, topic)
    return prediction

class LessonGenerator(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate_lesson = dspy.ChainOfThought('grade, topic -> lesson')

    def forward(self, grade_level, topic):
        return coppa_safe_lesson(self, grade_level, topic)

# Usage
lesson_gen = LessonGenerator()
lesson = lesson_gen(grade_level='3rd', topic='photosynthesis')

import dspy
import vex

@vex.verify(policies=[{'name': 'section_508', 'wcag_level': 'AA', 'screen_reader': True, 'math_accessible': True}],
           on_fail='rewrite')
def accessible_content(self, question):
    prediction = self.answer_question(question)
    return prediction

class AccessibleTutor(dspy.Module):
    def __init__(self):
        super().__init__()
        self.answer_question = dspy.ProgramOfThought('question -> accessible_answer')

    def forward(self, question):
        return accessible_content(self, question)

# Usage
accessible_tutor = AccessibleTutor()
answer = accessible_tutor('Solve 3x + 5 = 14')
